approach1.code:
body {
  font-family: system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, sans-serif;
  margin: 2rem;
  background: #fafafa;
  color: #111827;
  line-height: 1.6;
}

.gallery {
  display: grid;
  gap: 1rem;
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

@media (min-width: 1024px) {
  .gallery {
    grid-template-columns: repeat(4, minmax(0, 1fr));
  }
}

.card {
  min-width: 0;
  background: #222;
  color: #fff;
  border-radius: 8px;
  padding: 1rem;
}

.card h2 {
  margin: 0 0 0.5rem;
  font-size: 1rem;
  overflow-wrap: anywhere;
}

.card p {
  margin: 0;
  opacity: 0.85;
}

